// CreateRequest.js — with Gemini API auto-detection
// Gemini reads the description and auto-fills severity + resource type

import React, { useState } from 'react';
import { api } from '../services/api';

const PRESETS = [
  { name: 'Connaught Place', lat: 28.6315, lng: 77.2167 },
  { name: 'Lajpat Nagar',   lat: 28.5693, lng: 77.2439 },
  { name: 'Dwarka',          lat: 28.5921, lng: 77.0460 },
  { name: 'Rohini',          lat: 28.7041, lng: 77.1025 },
  { name: 'Saket',           lat: 28.5244, lng: 77.2066 },
];

const DEFAULT = {
  location: '',
  lat: '28.6139',
  lng: '77.2090',
  severity: 'medium',
  description: '',
  type: 'any',
};

export default function CreateRequest({ notify, goPage }) {
  const [form, setForm]           = useState(DEFAULT);
  const [loading, setLoading]     = useState(false);
  const [analyzing, setAnalyzing] = useState(false); // Gemini loading state
  const [aiResult, setAiResult]   = useState(null);  // stores Gemini suggestion

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  // ── Gemini API call ────────────────────────────────────────────────────────
  async function analyzeWithGemini() {
    if (!form.description.trim()) {
      notify('Empty description', 'Please enter a description first so Gemini can analyse it.');
      return;
    }

    setAnalyzing(true);
    setAiResult(null);

    try {
      const AIzaSyDmGHdfbpol1eMlsw4y2pMO3xNnOfu_4Lw = process.env.REACT_APP_GEMINI_API_KEY;

      const prompt = `
        You are an emergency dispatch AI assistant.
        Analyse the following emergency request description and return ONLY a JSON object with two fields:
        1. "severity": one of "high", "medium", or "low"
        2. "type": one of "Ambulance", "Responder", "Delivery", or "any"

        Rules:
        - Use "Ambulance" for medical emergencies, injuries, cardiac events, breathing issues, accidents
        - Use "Responder" for fires, crimes, riots, rescues, disasters, security threats
        - Use "Delivery" for supply needs like blood, medicine, oxygen, food, relief materials
        - Use "high" severity for life-threatening or immediate danger situations
        - Use "medium" severity for urgent but currently stable situations
        - Use "low" severity for non-urgent or routine requests
        - Return ONLY the JSON. No explanation. No markdown. No extra text.

        Description: "${form.description}"
      `;

      const response = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${AIzaSyDmGHdfbpol1eMlsw4y2pMO3xNnOfu_4Lw}`,
        {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            contents: [{ parts: [{ text: prompt }] }],
            generationConfig: {
              temperature: 0.1,      // low temperature = consistent, predictable output
              maxOutputTokens: 100,
            },
          }),
        }
      );

      const data = await response.json();

      // Extract text from Gemini response
      const rawText = data?.candidates?.[0]?.content?.parts?.[0]?.text || '';

      // Clean up any accidental markdown code fences
      const cleaned = rawText.replace(/```json|```/g, '').trim();

      // Parse the JSON Gemini returned
      const parsed = JSON.parse(cleaned);

      // Validate the values before applying
      const validSeverities = ['high', 'medium', 'low'];
      const validTypes      = ['Ambulance', 'Responder', 'Delivery', 'any'];

      const severity = validSeverities.includes(parsed.severity) ? parsed.severity : 'medium';
      const type     = validTypes.includes(parsed.type)          ? parsed.type     : 'any';

      // Auto-fill the form fields
      setForm(f => ({ ...f, severity, type }));

      // Show the result badge to the user
      setAiResult({ severity, type });

      notify('Gemini analysed!', `Severity → ${severity} | Type → ${type}`);

    } catch (err) {
      console.error('Gemini error:', err);
      notify('Gemini failed', 'Could not analyse description. Please set severity and type manually.');
    } finally {
      setAnalyzing(false);
    }
  }

  // ── Submit form ────────────────────────────────────────────────────────────
  async function handleSubmit() {
    if (!form.location || !form.lat || !form.lng) {
      notify('Missing fields', 'Please fill in location, latitude and longitude.');
      return;
    }
    setLoading(true);
    try {
      const req = await api.createRequest({
        ...form,
        lat: parseFloat(form.lat),
        lng: parseFloat(form.lng),
      });
      const alloc = await api.allocate(req.id);
      notify('Allocated!', `${alloc.resourceName} dispatched to ${req.location}`);
      setForm(DEFAULT);
      setAiResult(null);
      goPage(3);
    } catch (err) {
      notify('Error', err.message, 4500);
    } finally {
      setLoading(false);
    }
  }

  return (
    <>
      <p className="page-title">Create Request</p>

      <div className="card">
        <div className="card-title">Request details</div>
        <div className="form-grid">

          {/* Location */}
          <div className="form-group">
            <label>Location name *</label>
            <input
              value={form.location}
              onChange={e => set('location', e.target.value)}
              placeholder="e.g. Sector 12, Delhi"
            />
          </div>

          {/* Description + Gemini button */}
          <div className="form-group">
            <label>Description *</label>
            <input
              value={form.description}
              onChange={e => { set('description', e.target.value); setAiResult(null); }}
              placeholder="Describe the emergency in detail..."
            />
          </div>

          {/* Gemini Analyse button — full width */}
          <div className="form-group" style={{ gridColumn: '1 / -1' }}>
            <button
              className="btn"
              onClick={analyzeWithGemini}
              disabled={analyzing || !form.description.trim()}
              style={{
                background: analyzing ? '#f5f5f4' : '#4B6FE4',
                color: analyzing ? '#888' : '#fff',
                border: 'none',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                gap: 8,
                fontWeight: 600,
              }}
            >
              {analyzing ? '🤖 Gemini is analysing...' : '✨ Auto-detect with Gemini AI'}
            </button>

            {/* Show Gemini result */}
            {aiResult && (
              <div style={{
                marginTop: 8,
                padding: '8px 12px',
                background: '#E1F5EE',
                borderRadius: 8,
                fontSize: 13,
                color: '#085041',
                display: 'flex',
                gap: 16,
              }}>
                <span>🤖 Gemini detected:</span>
                <strong>Severity → {aiResult.severity}</strong>
                <strong>Type → {aiResult.type}</strong>
              </div>
            )}
          </div>

          {/* Severity — auto-filled by Gemini */}
          <div className="form-group">
            <label>Severity * <span style={{ color: '#4B6FE4', fontSize: 11 }}>(auto-filled by Gemini)</span></label>
            <select value={form.severity} onChange={e => set('severity', e.target.value)}>
              <option value="high">High — immediate danger</option>
              <option value="medium">Medium — urgent but stable</option>
              <option value="low">Low — non-urgent</option>
            </select>
          </div>

          {/* Resource type — auto-filled by Gemini */}
          <div className="form-group">
            <label>Resource type <span style={{ color: '#4B6FE4', fontSize: 11 }}>(auto-filled by Gemini)</span></label>
            <select value={form.type} onChange={e => set('type', e.target.value)}>
              <option value="any">Any available</option>
              <option value="Ambulance">🚑 Ambulance</option>
              <option value="Responder">🦺 Responder</option>
              <option value="Delivery">📦 Delivery</option>
            </select>
            <span style={{ fontSize: 11, color: 'var(--muted)', marginTop: 3 }}>
              Gemini sets this automatically — you can still override it manually.
            </span>
          </div>

          {/* Lat / Lng */}
          <div className="form-group">
            <label>Latitude *</label>
            <input
              type="number"
              step="0.0001"
              value={form.lat}
              onChange={e => set('lat', e.target.value)}
            />
          </div>
          <div className="form-group">
            <label>Longitude *</label>
            <input
              type="number"
              step="0.0001"
              value={form.lng}
              onChange={e => set('lng', e.target.value)}
            />
          </div>

        </div>

        <button
          className="btn primary full"
          onClick={handleSubmit}
          disabled={loading}
        >
          {loading ? 'Allocating…' : 'Submit + Auto-allocate'}
        </button>
      </div>

      {/* Preset chips */}
      <div className="card">
        <div className="card-title">Quick-fill presets</div>
        <div className="preset-chips">
          {PRESETS.map(p => (
            <button
              key={p.name}
              className="btn"
              onClick={() => setForm(f => ({ ...f, location: p.name, lat: String(p.lat), lng: String(p.lng) }))}
            >
              {p.name}
            </button>
          ))}
        </div>
      </div>
    </>
  );
}
